namespace sv_fc3471a776c848b198cf98911556750d.Services;

/// <summary>
/// Scoped service that holds the currently selected warehouse for a single user circuit.
/// Components subscribe to <see cref="OnChange"/> to react when the selection changes.
/// </summary>
public class WarehouseState
{
    public string SelectedWarehouseId { get; private set; } = "WH-1";
    public string SelectedWarehouseName => Warehouses[SelectedWarehouseId];

    public static readonly Dictionary<string, string> Warehouses = new()
    {
        ["WH-1"] = "Warehouse A — Main Distribution",
        ["WH-2"] = "Warehouse B — East Regional",
        ["WH-3"] = "Warehouse C — West Regional",
        ["WH-4"] = "Warehouse D — Returns Processing"
    };

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (SelectedWarehouseId == warehouseId) return;
        SelectedWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

namespace sv_fc3471a776c848b198cf98911556750d.Services;

/// <summary>
/// Simulates a database query that returns the number of low-stock items for a warehouse.
/// </summary>
public class InventoryAlertService
{
    private readonly Random _random = new();

    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulate async DB call with a random count between 0 and 15
        var count = _random.Next(0, 16);
        return Task.FromResult(count);
    }
}

