namespace sv_fc3471a776c848b198cf98911556750d.Services;

/// <summary>
/// Scoped service that holds the current low-stock alert count and notifies all subscribers
/// when new data arrives. This enables cross-component communication (e.g., sidebar badge
/// and dashboard page) without a parent-child relationship.
/// </summary>
public class InventoryAlertState
{
    public int LowStockCount { get; private set; }

    public event Action? OnChange;

    public void UpdateCount(int newCount)
    {
        LowStockCount = newCount;
        OnChange?.Invoke();
    }
}

