@page "/dashboard"
@rendermode InteractiveServer
@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService
@inject InventoryAlertState AlertState
@implements IDisposable

<PageTitle>Dashboard — @WarehouseState.SelectedWarehouseName</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mb-4">
    <div class="card-header">
        <strong>@WarehouseState.SelectedWarehouseName</strong>
    </div>
    <div class="card-body">
        <div class="row">
            <div class="col-md-4">
                <div class="card text-bg-@(AlertState.LowStockCount > 5 ? "danger" : AlertState.LowStockCount > 0 ? "warning" : "success")">
                    <div class="card-body text-center">
                        <h5 class="card-title">Low-Stock Alerts</h5>
                        <p class="display-4">@AlertState.LowStockCount</p>
                        <p class="card-text">items below minimum level</p>
                    </div>
                </div>
            </div>
            <div class="col-md-8">
                <p class="text-muted mt-2">
                    Live polling every 10 seconds for <strong>@WarehouseState.SelectedWarehouseName</strong>.
                    Last checked: @_lastChecked?.ToString("HH:mm:ss") ?? "—"
                </p>
                @if (_isPolling)
                {
                    <span class="badge bg-info">● Polling active</span>
                }
            </div>
        </div>
    </div>
</div>

@code {
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private DateTime? _lastChecked;
    private bool _isPolling;
    private Action? _warehouseHandler;

    protected override async Task OnInitializedAsync()
    {
        // Subscribe to warehouse changes so polling restarts with the new warehouse
        _warehouseHandler = () => InvokeAsync(OnWarehouseChanged);
        WarehouseState.OnChange += _warehouseHandler;

        // Subscribe to alert state changes pushed by other components or this one
        AlertState.OnChange += OnAlertChanged;

        await StartPollingAsync();
    }

    private async void OnWarehouseChanged()
    {
        // Restart polling for the newly selected warehouse
        StopPolling();
        await FetchAndNotifyAsync();
        await StartPollingAsync();
        StateHasChanged();
    }

    private void OnAlertChanged() => InvokeAsync(StateHasChanged);

    private async Task StartPollingAsync()
    {
        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        _isPolling = true;

        // Initial fetch
        await FetchAndNotifyAsync();

        // Background polling loop
        _ = PollLoopAsync(_cts.Token);
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        try
        {
            while (await _timer!.WaitForNextTickAsync(ct))
            {
                await FetchAndNotifyAsync();
            }
        }
        catch (OperationCanceledException)
        {
            // Expected on dispose or warehouse change
        }
    }

    private async Task FetchAndNotifyAsync()
    {
        var count = await AlertService.GetLowStockCountAsync(WarehouseState.SelectedWarehouseId);
        _lastChecked = DateTime.Now;
        // Push to shared state — this notifies ALL subscribers (sidebar badge, etc.)
        AlertState.UpdateCount(count);
    }

    private void StopPolling()
    {
        _isPolling = false;
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
        _timer?.Dispose();
        _timer = null;
    }

    public void Dispose()
    {
        StopPolling();
        WarehouseState.OnChange -= _warehouseHandler;
        AlertState.OnChange -= OnAlertChanged;
    }
}

